mapper.select:
SELECT r.id, r.building_id AS buildingId, r.park_id AS parkId, b.name AS buildingName, p.name AS parkName, r.name, r.floor, r.area, r.rent_price AS rentPrice, r.property_fee AS propertyFee, r.status FROM ics_room r LEFT JOIN ics_building b ON b.id = r.building_id LEFT JOIN ics_park p ON p.id = r.park_id WHERE r.id IN
#{roomId}
ORDER BY p.name ASC, b.name ASC, r.floor ASC, r.name ASC
